@using sv_10336d3205eb4f8e8638271622014b02.Models

<div class="list-group settings-sidebar">
    @foreach (var section in Sections)
    {
        <button type="button"
                class="list-group-item list-group-item-action d-flex align-items-center gap-2 @(section.Key == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionSelected.InvokeAsync(section.Key)">
            <i class="bi @section.Icon"></i>
            @section.Label
        </button>
    }
</div>

@code {
    [Parameter] public string ActiveSection { get; set; } = "profile";
    [Parameter] public EventCallback<string> OnSectionSelected { get; set; }

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] Sections =
    [
        new("profile", "Profile", "bi-person-circle"),
        new("notifications", "Notifications", "bi-bell"),
        new("security", "Security", "bi-shield-lock"),
        new("appearance", "Appearance", "bi-palette"),
    ];
}

@using sv_10336d3205eb4f8e8638271622014b02.Models

<div class="card">
    <div class="card-header d-flex justify-content-between align-items-center">
        <h5 class="mb-0">Profile Settings</h5>
    </div>
    <div class="card-body">
        @if (_statusMessage is not null)
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="row mb-4">
            <div class="col-md-3 text-center">
                <div class="mb-2">
                    <img src="@_avatarUrl" alt="Avatar" class="rounded-circle border" width="120" height="120"
                         onerror="this.style.display='none'" />
                </div>
                <small class="text-muted text-break">@_avatarUrl</small>
            </div>
            <div class="col-md-9">
                <div class="mb-3">
                    <label class="form-label fw-semibold">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label fw-semibold">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>
                <div class="mb-3">
                    <label class="form-label fw-semibold">Avatar URL</label>
                    <input type="url" class="form-control" @bind="_avatarUrl" />
                </div>
                <div class="mb-3">
                    <label class="form-label fw-semibold">Bio</label>
                    <textarea class="form-control" rows="3" @bind="_bio"></textarea>
                </div>
            </div>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public UserProfile Profile { get; set; } = default!;
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    protected override void OnParametersSet()
    {
        if (!_saving)
            LoadFromProfile();
    }

    private void LoadFromProfile()
    {
        _displayName = Profile.DisplayName;
        _email = Profile.Email;
        _avatarUrl = Profile.AvatarUrl;
        _bio = Profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await OnSave.InvokeAsync(updated);
            _statusMessage = "Profile saved successfully!";
            _isError = false;
        }
        catch
        {
            _statusMessage = "Failed to save profile. Please try again.";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        LoadFromProfile();
        _statusMessage = null;
    }
}

@using sv_10336d3205eb4f8e8638271622014b02.Models

<div class="card">
    <div class="card-header">
        <h5 class="mb-0">Notification Preferences</h5>
    </div>
    <div class="card-body">
        @if (_statusMessage is not null)
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="mb-4">
            <h6 class="text-muted mb-3">General</h6>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch" id="emailNotif"
                       checked="@_emailNotifications" @onchange="e => _emailNotifications = (bool)e.Value!" />
                <label class="form-check-label" for="emailNotif">
                    <strong>Email Notifications</strong>
                    <br /><small class="text-muted">Receive notifications via email</small>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch" id="pushNotif"
                       checked="@_pushNotifications" @onchange="e => _pushNotifications = (bool)e.Value!" />
                <label class="form-check-label" for="pushNotif">
                    <strong>Push Notifications</strong>
                    <br /><small class="text-muted">Receive push notifications on your device</small>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch" id="weeklyDigest"
                       checked="@_weeklyDigest" @onchange="e => _weeklyDigest = (bool)e.Value!" />
                <label class="form-check-label" for="weeklyDigest">
                    <strong>Weekly Digest</strong>
                    <br /><small class="text-muted">Get a weekly summary of activity</small>
                </label>
            </div>
        </div>

        <div class="mb-4">
            <h6 class="text-muted mb-3">Muted Channels</h6>
            @foreach (var channel in AllChannels)
            {
                var isMuted = _mutedChannels.Contains(channel);
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@isMuted"
                           @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        #@channel
                        @if (isMuted)
                        {
                            <span class="badge bg-secondary ms-1">muted</span>
                        }
                    </label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Preferences
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs Prefs { get; set; } = default!;
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private static readonly List<string> AllChannels =
        ["general", "announcements", "random", "engineering", "design", "marketing"];

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private bool _saving;
    private string? _statusMessage;

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            _emailNotifications = Prefs.EmailNotifications;
            _pushNotifications = Prefs.PushNotifications;
            _weeklyDigest = Prefs.WeeklyDigest;
            _mutedChannels = [.. Prefs.MutedChannels];
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted) _mutedChannels.Add(channel);
        else _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        var updated = new NotificationPrefs(
            _emailNotifications, _pushNotifications, _weeklyDigest, [.. _mutedChannels]);
        await OnSave.InvokeAsync(updated);
        _statusMessage = "Notification preferences saved!";
        _saving = false;
    }
}

@using sv_10336d3205eb4f8e8638271622014b02.Models

<div class="card">
    <div class="card-header">
        <h6 class="mb-0">Active Sessions</h6>
    </div>
    <div class="table-responsive">
        <table class="table table-hover mb-0 align-middle">
            <thead class="table-light">
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th class="text-end">Action</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Sessions)
                {
                    var isCurrent = session.Id == CurrentSessionId;
                    <tr>
                        <td>
                            @session.Device
                            @if (isCurrent)
                            {
                                <span class="badge bg-success ms-1">Current</span>
                            }
                        </td>
                        <td>@session.Location</td>
                        <td>@FormatLastActive(session.LastActive)</td>
                        <td class="text-end">
                            @if (!isCurrent)
                            {
                                <button class="btn btn-sm btn-outline-danger"
                                        @onclick="() => RequestRevoke(session)">
                                    Revoke
                                </button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
</div>

@* Confirmation dialog *@
@if (_sessionToRevoke is not null)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session for <strong>@_sessionToRevoke.Device</strong> in @_sessionToRevoke.Location?</p>
                    <p class="text-muted mb-0">This will sign the device out immediately.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                        @if (_revoking)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Revoke Session
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    private void RequestRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
        _revoking = false;
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@using sv_10336d3205eb4f8e8638271622014b02.Models

<div class="card">
    <div class="card-header">
        <h5 class="mb-0">Security Settings</h5>
    </div>
    <div class="card-body">
        <ChangePasswordPanel OnChangePassword="OnChangePassword" />

        <div class="card mb-3">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <small class="text-muted">
                        @if (Settings.TwoFactorEnabled)
                        {
                            <span class="text-success"><i class="bi bi-check-circle-fill me-1"></i>Enabled</span>
                        }
                        else
                        {
                            <span class="text-warning"><i class="bi bi-exclamation-triangle-fill me-1"></i>Disabled</span>
                        }
                    </small>
                    @if (Settings.LastPasswordChange.HasValue)
                    {
                        <br />
                        <small class="text-muted">Last password change: @Settings.LastPasswordChange.Value.ToString("MMM dd, yyyy")</small>
                    }
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_twoFactorEnabled"
                           @onchange="Toggle2FA" />
                </div>
            </div>
        </div>

        <ActiveSessionsTable Sessions="Settings.Sessions" OnRevoke="OnRevokeSession" />
    </div>
</div>

@code {
    [Parameter, EditorRequired] public SecuritySettings Settings { get; set; } = default!;
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }
    [Parameter] public EventCallback<bool> OnToggle2FA { get; set; }

    private bool _twoFactorEnabled;

    protected override void OnParametersSet()
    {
        _twoFactorEnabled = Settings.TwoFactorEnabled;
    }

    private async Task Toggle2FA(ChangeEventArgs e)
    {
        _twoFactorEnabled = (bool)e.Value!;
        await OnToggle2FA.InvokeAsync(_twoFactorEnabled);
    }
}

