                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-3 col-lg-2 mb-3">
                <SettingsSidebar ActiveSection="@_activeSection"
                                OnSectionSelected="s => _activeSection = s" />
            </div>
