{"file_text": "@using sv_10336d3205eb4f8e8638271622014b02.Models

<div class="card">
    <div class="card-header">
        <h5 class="mb-0">Appearance</h5>
    </div>
    <div class="card-body">
        @if (_statusMessage is not null)
        {
            <div class="alert alert-success alert-dismissible fade show">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-6">
                <div class="mb-4">
                    <h6 class="text-muted mb-2">Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h6 class="text-muted mb-2">Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h6 class="text-muted mb-2">Language</h6>
                    <select class="form-select" @bind="_language">
                        <option value="English">English</option>
                        <option value="Spanish">Spanish</option>
                        <option value="French">French</option>
                        <option value="German">German</option>
                        <option value="Japanese">Japanese</option>
                        <option value="Chinese">Chinese</option>
                    </select>
                </div>

                <div class="mb-4">
                    <h6 class="text-muted mb-2">Compact Mode</h6>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" id="compactMode"
                               checked="@_compactMode"
                               @onchange="e => _compactMode = (bool)e.Value!" />
                        <label class="form-check-label" for="compactMode">
                            Reduce spacing and padding
                        </label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @if (_saving)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Save
                </button>
            </div>

            @* Live preview panel *@
            <div class="col-md-6">
                <h6 class="text-muted mb-2">Preview</h6>
                <div class="border rounded @PreviewBgClass @PreviewTextClass"
                     style="@PreviewStyle">
                    <div class="@PreviewPadding">
                        <div class="d-flex align-items-center mb-2">
                            <div class="rounded-circle bg-primary d-flex align-items-center justify-content-center text-white"
                                 style="width:32px;height:32px;">
                                <span style="font-size:0.8rem">JD</span>
                            </div>
                            <strong class="ms-2">Jane Doe</strong>
                        </div>
                        <p class="mb-2">This is a preview of how your content will look with the selected appearance settings.</p>
                        <div class="d-flex gap-2">
                            <button class="btn btn-sm btn-primary">Primary</button>
                            <button class="btn btn-sm btn-outline-secondary">Secondary</button>
                        </div>
                        <hr />
                        <ul class="list-unstyled mb-0">
                            <li class="@PreviewItemPadding">📧 Inbox <span class="badge bg-primary rounded-pill">3</span></li>
                            <li class="@PreviewItemPadding">📋 Tasks <span class="badge bg-secondary rounded-pill">12</span></li>
                            <li class="@PreviewItemPadding">⚙️ Settings</li>
                        </ul>
                    </div>
                </div>
                <small class="text-muted mt-1 d-block">
                    Theme: @_theme · Font: @_fontSize · Language: @_language · Compact: @(_compactMode ? "On" : "Off")
                </small>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings Settings { get; set; } = default!;
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _saving;
    private string? _statusMessage;

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            _theme = Settings.Theme;
            _fontSize = Settings.FontSize;
            _language = Settings.Language;
            _compactMode = Settings.CompactMode;
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await OnSave.InvokeAsync(updated);
        _statusMessage = "Appearance settings saved!";
        _saving = false;
    }

    private string PreviewBgClass => _theme switch
    {
        "Dark" => "bg-dark text-white",
        _ => "bg-white text-dark"
    };

    private string PreviewTextClass => _theme == "Dark" ? "text-white" : "text-dark";

    private string PreviewStyle => _fontSize switch
    {
        "Small" => "font-size: 0.8rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 0.95rem;"
    };

    private string PreviewPadding => _compactMode ? "p-2" : "p-3";
    private string PreviewItemPadding => _compactMode ? "py-1" : "py-2";
}
