        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public UserProfile Profile { get; set; } = default!;
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    protected override void OnParametersSet()
    {
        if (!_saving)
            LoadFromProfile();
    }

    private void LoadFromProfile()
    {
        _displayName = Profile.DisplayName;
        _email = Profile.Email;
        _avatarUrl = Profile.AvatarUrl;
        _bio = Profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await OnSave.InvokeAsync(updated);
            _statusMessage = "Profile saved successfully!";
            _isError = false;
        }
        catch
        {
            _statusMessage = "Failed to save profile. Please try again.";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        LoadFromProfile();
        _statusMessage = null;
    }
}

