            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch" id="pushNotif"
                       checked="@_pushNotifications" @onchange="e => _pushNotifications = (bool)e.Value!" />
                <label class="form-check-label" for="pushNotif">
                    <strong>Push Notifications</strong>
                    <br /><small class="text-muted">Receive push notifications on your device</small>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch" id="weeklyDigest"
                       checked="@_weeklyDigest" @onchange="e => _weeklyDigest = (bool)e.Value!" />
                <label class="form-check-label" for="weeklyDigest">
                    <strong>Weekly Digest</strong>
                    <br /><small class="text-muted">Get a weekly summary of activity</small>
                </label>
            </div>
        </div>

        <div class="mb-4">
            <h6 class="text-muted mb-3">Muted Channels</h6>
            @foreach (var channel in AllChannels)
            {
                var isMuted = _mutedChannels.Contains(channel);
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@isMuted"
                           @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        #@channel
                        @if (isMuted)
                        {
                            <span class="badge bg-secondary ms-1">muted</span>
                        }
                    </label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Preferences
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs Prefs { get; set; } = default!;
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private static readonly List<string> AllChannels =
        ["general", "announcements", "random", "engineering", "design", "marketing"];

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private bool _saving;
    private string? _statusMessage;

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            _emailNotifications = Prefs.EmailNotifications;
            _pushNotifications = Prefs.PushNotifications;
            _weeklyDigest = Prefs.WeeklyDigest;
            _mutedChannels = [.. Prefs.MutedChannels];
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted) _mutedChannels.Add(channel);
        else _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        var updated = new NotificationPrefs(
            _emailNotifications, _pushNotifications, _weeklyDigest, [.. _mutedChannels]);
        await OnSave.InvokeAsync(updated);
        _statusMessage = "Notification preferences saved!";
        _saving = false;
    }
}

