@using sv_10336d3205eb4f8e8638271622014b02.Models

<div class="card">
    <div class="card-header">
        <h5 class="mb-0">Security Settings</h5>
    </div>
    <div class="card-body">
        <ChangePasswordPanel OnChangePassword="OnChangePassword" />

        <div class="card mb-3">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <small class="text-muted">
                        @if (Settings.TwoFactorEnabled)
                        {
                            <span class="text-success"><i class="bi bi-check-circle-fill me-1"></i>Enabled</span>
                        }
                        else
                        {
                            <span class="text-warning"><i class="bi bi-exclamation-triangle-fill me-1"></i>Disabled</span>
                        }
                    </small>
                    @if (Settings.LastPasswordChange.HasValue)
                    {
                        <br />
                        <small class="text-muted">Last password change: @Settings.LastPasswordChange.Value.ToString("MMM dd, yyyy")</small>
                    }
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_twoFactorEnabled"
                           @onchange="Toggle2FA" />
                </div>
            </div>
        </div>

        <ActiveSessionsTable Sessions="Settings.Sessions" OnRevoke="OnRevokeSession" />
    </div>
</div>

@code {
    [Parameter, EditorRequired] public SecuritySettings Settings { get; set; } = default!;
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }
    [Parameter] public EventCallback<bool> OnToggle2FA { get; set; }

    private bool _twoFactorEnabled;

    protected override void OnParametersSet()
    {
        _twoFactorEnabled = Settings.TwoFactorEnabled;
    }

    private async Task Toggle2FA(ChangeEventArgs e)
    {
        _twoFactorEnabled = (bool)e.Value!;
        await OnToggle2FA.InvokeAsync(_twoFactorEnabled);
    }
}

@using sv_10336d3205eb4f8e8638271622014b02.Models

<div class="card">
    <div class="card-header">
        <h5 class="mb-0">Appearance</h5>
    </div>
    <div class="card-body">
        @if (_statusMessage is not null)
        {
            <div class="alert alert-success alert-dismissible fade show">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-6">
                <div class="mb-4">
                    <h6 class="text-muted mb-2">Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h6 class="text-muted mb-2">Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h6 class="text-muted mb-2">Language</h6>
                    <select class="form-select" @bind="_language">
                        <option value="English">English</option>
                        <option value="Spanish">Spanish</option>
                        <option value="French">French</option>
                        <option value="German">German</option>
                        <option value="Japanese">Japanese</option>
                        <option value="Chinese">Chinese</option>
                    </select>
                </div>

                <div class="mb-4">
                    <h6 class="text-muted mb-2">Compact Mode</h6>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch" id="compactMode"
                               checked="@_compactMode"
                               @onchange="e => _compactMode = (bool)e.Value!" />
                        <label class="form-check-label" for="compactMode">
                            Reduce spacing and padding
                        </label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @if (_saving)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Save
                </button>
            </div>

            @* Live preview panel *@
            <div class="col-md-6">
                <h6 class="text-muted mb-2">Preview</h6>
                <div class="border rounded @PreviewBgClass @PreviewTextClass"
                     style="@PreviewStyle">
                    <div class="@PreviewPadding">
                        <div class="d-flex align-items-center mb-2">
                            <div class="rounded-circle bg-primary d-flex align-items-center justify-content-center text-white"
                                 style="width:32px;height:32px;">
                                <span style="font-size:0.8rem">JD</span>
                            </div>
                            <strong class="ms-2">Jane Doe</strong>
                        </div>
                        <p class="mb-2">This is a preview of how your content will look with the selected appearance settings.</p>
                        <div class="d-flex gap-2">
                            <button class="btn btn-sm btn-primary">Primary</button>
                            <button class="btn btn-sm btn-outline-secondary">Secondary</button>
                        </div>
                        <hr />
                        <ul class="list-unstyled mb-0">
                            <li class="@PreviewItemPadding">📧 Inbox <span class="badge bg-primary rounded-pill">3</span></li>
                            <li class="@PreviewItemPadding">📋 Tasks <span class="badge bg-secondary rounded-pill">12</span></li>
                            <li class="@PreviewItemPadding">⚙️ Settings</li>
                        </ul>
                    </div>
                </div>
                <small class="text-muted mt-1 d-block">
                    Theme: @_theme · Font: @_fontSize · Language: @_language · Compact: @(_compactMode ? "On" : "Off")
                </small>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings Settings { get; set; } = default!;
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _saving;
    private string? _statusMessage;

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            _theme = Settings.Theme;
            _fontSize = Settings.FontSize;
            _language = Settings.Language;
            _compactMode = Settings.CompactMode;
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await OnSave.InvokeAsync(updated);
        _statusMessage = "Appearance settings saved!";
        _saving = false;
    }

    private string PreviewBgClass => _theme switch
    {
        "Dark" => "bg-dark text-white",
        _ => "bg-white text-dark"
    };

    private string PreviewTextClass => _theme == "Dark" ? "text-white" : "text-dark";

    private string PreviewStyle => _fontSize switch
    {
        "Small" => "font-size: 0.8rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 0.95rem;"
    };

    private string PreviewPadding => _compactMode ? "p-2" : "p-3";
    private string PreviewItemPadding => _compactMode ? "py-1" : "py-2";
}

@page "/settings"
@using sv_10336d3205eb4f8e8638271622014b02.Models
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="container-fluid py-4">
    <h3 class="mb-4">Settings</h3>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-3 col-lg-2 mb-3">
                <SettingsSidebar ActiveSection="@_activeSection"
                                OnSectionSelected="s => _activeSection = s" />
            </div>
            <div class="col-md-9 col-lg-10">
                @switch (_activeSection)
                {
                    case "profile":
                        <ProfileSection Profile="_profile!" OnSave="SaveProfileAsync" />
                        break;
                    case "notifications":
                        <NotificationsSection Prefs="_notificationPrefs!" OnSave="SaveNotificationsAsync" />
                        break;
                    case "security":
                        <SecuritySection Settings="_securitySettings!"
                                         OnChangePassword="ChangePasswordAsync"
                                         OnRevokeSession="RevokeSessionAsync"
                                         OnToggle2FA="Toggle2FAAsync" />
                        break;
                    case "appearance":
                        <AppearanceSection Settings="_appearanceSettings!" OnSave="SaveAppearanceAsync" />
                        break;
                }
            </div>
        </div>
    }
</div>

@code {
    private string _activeSection = "profile";
    private bool _loading = true;

    private UserProfile? _profile;
    private NotificationPrefs? _notificationPrefs;
    private SecuritySettings? _securitySettings;
    private AppearanceSettings? _appearanceSettings;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllAsync();
        _loading = false;
    }

    private async Task LoadAllAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        _profile = profileTask.Result;
        _notificationPrefs = notifTask.Result;
        _securitySettings = securityTask.Result;
        _appearanceSettings = appearanceTask.Result;
    }

    private async Task SaveProfileAsync(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
    }

    private async Task SaveNotificationsAsync(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notificationPrefs = prefs;
    }

    private async Task ChangePasswordAsync((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
    }

    private Task Toggle2FAAsync(bool enabled)
    {
        // In a real app this would call the service
        return Task.CompletedTask;
    }

    private async Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearanceSettings = settings;
    }
}

